changeSet.sql:
WITH x3_tests(loinc, unit_name, test_name, report_name, local_code, sort_order) AS ( VALUES ('14928-6', 'pmol/L', 'Free T3', 'Free T3', 'X3-FT3-Serum', 300), ('3024-7', 'ng/dL', 'Free T4', 'Free T4', 'X3-FT4II-Serum', 301), ('3016-3', 'uIU/mL', 'TSH', 'TSH', 'X3-TSHII-Serum', 302) ) UPDATE clinlims.test t SET uom_id = COALESCE(( SELECT min(u.id) FROM clinlims.unit_of_measure u WHERE lower(u.name) = lower(v.unit_name) OR lower(u.description) = lower(v.unit_name) OR u.code = v.unit_name), t.uom_id), is_active = 'Y', orderable = true, lastupdated = now() FROM x3_tests v WHERE t.loinc = v.loinc;
WITH x3_tests(loinc, unit_name, test_name, report_name, local_code, sort_order) AS ( VALUES ('14928-6', 'pmol/L', 'Free T3', 'Free T3', 'X3-FT3-Serum', 300), ('3024-7', 'ng/dL', 'Free T4', 'Free T4', 'X3-FT4II-Serum', 301), ('3016-3', 'uIU/mL', 'TSH', 'TSH', 'X3-TSHII-Serum', 302) ) INSERT INTO clinlims.test (id, name, description, reporting_description, loinc, is_active, orderable, test_section_id, uom_id, local_code, sort_order, guid, lastupdated) SELECT nextval('clinlims.test_seq'), v.test_name, v.test_name || '(Serum)', v.report_name, v.loinc, 'Y', true, (SELECT ts.id FROM clinlims.test_section ts WHERE ts.name IN ('Immunology', 'Serology', 'Biochemistry') OR ts.description = 'Chem logbook' ORDER BY CASE ts.name WHEN 'Immunology' THEN 0 WHEN 'Serology' THEN 1 ELSE 2 END, ts.id LIMIT 1), (SELECT min(u.id) FROM clinlims.unit_of_measure u WHERE lower(u.name) = lower(v.unit_name) OR lower(u.description) = lower(v.unit_name) OR u.code = v.unit_name), v.local_code, v.sort_order, gen_random_uuid()::varchar, now() FROM x3_tests v WHERE NOT EXISTS (SELECT 1 FROM clinlims.test t WHERE t.loinc = v.loinc);
WITH x3_tests(loinc, sort_order) AS ( VALUES ('14928-6', 300), ('3024-7', 301), ('3016-3', 302) ) INSERT INTO clinlims.sampletype_test (id, sample_type_id, test_id, is_panel, display_order) SELECT nextval('clinlims.sample_type_test_seq'), (SELECT min(s.id) FROM clinlims.type_of_sample s WHERE lower(s.description) = 'serum' OR lower(s.local_abbrev) = 'serum'), (SELECT min(t.id) FROM clinlims.test t WHERE t.loinc = v.loinc), false, v.sort_order FROM x3_tests v WHERE EXISTS (SELECT 1 FROM clinlims.test t WHERE t.loinc = v.loinc) AND EXISTS ( SELECT 1 FROM clinlims.type_of_sample s WHERE lower(s.description) = 'serum' OR lower(s.local_abbrev) = 'serum') AND NOT EXISTS ( SELECT 1 FROM clinlims.sampletype_test st WHERE st.sample_type_id = ( SELECT min(s.id) FROM clinlims.type_of_sample s WHERE lower(s.description) = 'serum' OR lower(s.local_abbrev) = 'serum') AND st.test_id = ( SELECT min(t.id) FROM clinlims.test t WHERE t.loinc = v.loinc));

rollback.sql:
DELETE FROM clinlims.sampletype_test
 WHERE test_id IN (
    SELECT id FROM clinlims.test WHERE local_code LIKE 'X3-%-Serum');

DELETE FROM clinlims.test
 WHERE local_code LIKE 'X3-%-Serum'
   AND loinc IN ('14928-6', '3024-7', '3016-3');

DELETE FROM clinlims.test_result
 WHERE test_id IN (
    SELECT id FROM clinlims.test WHERE local_code LIKE 'X3-%-Serum');

DELETE FROM clinlims.analyzer_test_map
 WHERE analyzer_test_name IN ('FT3', 'FT4 II', 'TSH II')
   AND analyzer_id IN (SELECT id FROM clinlims.analyzer WHERE name = 'SNIBE MAGLUMI X3');
